mapper.select:
SELECT n.notification_id AS notificationId, n.recipient_id AS recipientId, n.actor_id AS actorId, COALESCE(NULLIF(actor.display_name, ''), actor.username, '') AS actorName, actor.avatar_url AS actorAvatarUrl, n.notification_type AS notificationType, n.target_type AS targetType, n.target_id AS targetId, n.post_id AS postId, n.help_id AS helpId, n.comment_id AS commentId, n.answer_id AS answerId, n.friend_request_id AS friendRequestId, n.title AS title, n.content AS content, n.read_flag AS readFlag, n.created_time AS createdTime, n.read_time AS readTime FROM notifications n LEFT JOIN users actor ON actor.user_id = n.actor_id WHERE n.recipient_id = #{recipientId}
AND n.read_flag = 0
ORDER BY n.created_time DESC, n.notification_id DESC LIMIT #{limit}

mapper.update:
UPDATE notifications
SET
    read_flag = 1,
    read_time = COALESCE(read_time, CURRENT_TIMESTAMP)
WHERE recipient_id = #{recipientId}
  AND notification_id = #{notificationId}
